import{bV as a,aL as t,u as i,G as e}from"./chunks/framework.BfzMay2U.js";const k=JSON.parse('{"title":"Docker安装MongoDB","description":"","frontmatter":{"title":"Docker安装MongoDB","date":"2023-06-17T23:36:10.000Z","categories":["Deploy"],"tags":["docker","MongoDB"]},"headers":[],"relativePath":"views/deploy/docker-mongodb-install.md","filePath":"views/deploy/docker-mongodb-install.md"}'),n={name:"views/deploy/docker-mongodb-install.md"};function l(d,s,o,p,r,h){return t(),i("div",null,[...s[0]||(s[0]=[e(`<h1 id="docker安装mongodb" tabindex="-1">Docker安装MongoDB <a class="header-anchor" href="#docker安装mongodb" aria-label="Permalink to &quot;Docker安装MongoDB&quot;">​</a></h1><h2 id="安装-mongo-镜像" tabindex="-1">安装 mongo 镜像 <a class="header-anchor" href="#安装-mongo-镜像" aria-label="Permalink to &quot;安装 mongo 镜像&quot;">​</a></h2><p>可以搜索一下有什么适合你的版本的我这里下的是<kbd>4.4.7</kbd></p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mongo</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mongo:4.4.7</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="配置本地卷" tabindex="-1">配置本地卷 <a class="header-anchor" href="#配置本地卷" aria-label="Permalink to &quot;配置本地卷&quot;">​</a></h2><p>在你们合适的目录新建对应的进行映射的目录，我是在用户目录下新建了一个<code>mydata/mongo</code>文件夹，用于存储映射的一些相关的文件。</p><p>需要在目录下新建一个配置文件：<code>mongod.conf</code></p><div class="language-conf vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">net:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   port: 27017</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   bindIp: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.0.0.0&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">storage:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   dbPath: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;/data/db&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">security:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">   authorization: enabled</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><div class="tip custom-block"><p class="custom-block-title">提示</p><p>MacOS 无法使用<code>root</code>目录，所以我们需要换成其他的目录，别的系统的就算了。</p></div><h2 id="创建容器运行" tabindex="-1">创建容器运行 <a class="header-anchor" href="#创建容器运行" aria-label="Permalink to &quot;创建容器运行&quot;">​</a></h2><blockquote><p>创建容器，为 MongoDB 分配 500M 内存</p></blockquote><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -it</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mongo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 27017:27017</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-v </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/Users/yourname/mydata/mongo:/etc/mongo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 500m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MONGO_INITDB_ROOT_USERNAME=admin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">MONGO_INITDB_ROOT_PASSWORD=admin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">-e </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TZ=Asia/Shanghai</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">mongo:4.4.7 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">--config</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/mongo/mongod.conf</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><ul><li>MONGO_INITDB_ROOT_USERNAME: 设置用户名</li><li>MONGO_INITDB_ROOT_PASSWORD: 设置密码</li></ul><h2 id="本地连接测试" tabindex="-1">本地连接测试 <a class="header-anchor" href="#本地连接测试" aria-label="Permalink to &quot;本地连接测试&quot;">​</a></h2><blockquote><p>使用 navicate 进行连接测试</p></blockquote><div class="warning custom-block"><p class="custom-block-title">注意主机名</p><p>先前我默认是<code>localhost</code>，出现错误，后来也换了我本机的<code>ip</code>地址进行测试，谁知道最后直接<code>127.0.0.1</code>就可以。</p></div><h2 id="mongo-语法" tabindex="-1">Mongo 语法 <a class="header-anchor" href="#mongo-语法" aria-label="Permalink to &quot;Mongo 语法&quot;">​</a></h2><blockquote><p>MySQL 和 Mongo 的对比</p></blockquote><table tabindex="0"><thead><tr><th>SQL</th><th>Mongo</th></tr></thead><tbody><tr><td>表 Table</td><td>集合 Collection</td></tr><tr><td>行 Row</td><td>文档 Document</td></tr><tr><td>列 Col</td><td>字段 Field</td></tr><tr><td>主键 Primary Key</td><td>对象 ID ObjectId</td></tr></tbody></table><blockquote><p>数据库操作</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:center;">创建数据库</th><th style="text-align:center;">Use demo</th></tr></thead><tbody><tr><td style="text-align:center;">查看数据库</td><td style="text-align:center;">show dbs</td></tr><tr><td style="text-align:center;">删除数据库</td><td style="text-align:center;">db.dropDatabase()</td></tr></tbody></table><blockquote><p>集合操作</p></blockquote><table tabindex="0"><thead><tr><th>创建集合</th><th>db.createCollection(name)</th></tr></thead><tbody><tr><td>查看集合</td><td>show collections</td></tr><tr><td>删除集合</td><td>db.collection.drop()</td></tr></tbody></table><blockquote><p>文档操作</p></blockquote><table tabindex="0"><thead><tr><th>创建文档</th><th>db.collection.insertOne({}) db.collection.insertMany([])</th></tr></thead><tbody><tr><td>查看文档</td><td>db.collections.find({})</td></tr><tr><td>删除文档</td><td>db.collection.deleteOne() db.collection.deleteMany()</td></tr><tr><td>更新文档</td><td>db.collection.update({}, {}, false, true)</td></tr></tbody></table><blockquote><p>条件操作</p></blockquote><table tabindex="0"><thead><tr><th>大于</th><th>$gt</th></tr></thead><tbody><tr><td>小于</td><td>$lt</td></tr><tr><td>大于等于</td><td>$gte</td></tr><tr><td>小于等于</td><td>$lte</td></tr></tbody></table>`,28)])])}const b=a(n,[["render",l]]);export{k as __pageData,b as default};
